#!/bin/bash

# ============================================
# CampusOne App Icon Generator
# ============================================
# This script generates all required iOS app icon sizes
# from a single source image (1024x1024 recommended)
#
# Requirements:
# - ImageMagick (install with: brew install imagemagick)
# - A source icon image (PNG, 1024x1024 pixels recommended)
#
# Usage:
#   chmod +x generate_app_icons.sh
#   ./generate_app_icons.sh path/to/your/icon.png
# ============================================

set -e

# Colors for output
RED='\033[0;31m'
GREEN='\033[0;32m'
YELLOW='\033[1;33m'
NC='\033[0m' # No Color

# Check if ImageMagick is installed
if ! command -v convert &> /dev/null; then
    echo -e "${RED}Error: ImageMagick is not installed.${NC}"
    echo "Install it with: brew install imagemagick"
    exit 1
fi

# Check if source image is provided
if [ -z "$1" ]; then
    echo -e "${RED}Error: No source image provided.${NC}"
    echo "Usage: ./generate_app_icons.sh path/to/your/icon.png"
    exit 1
fi

SOURCE_ICON="$1"

# Check if source file exists
if [ ! -f "$SOURCE_ICON" ]; then
    echo -e "${RED}Error: Source image '$SOURCE_ICON' not found.${NC}"
    exit 1
fi

# Create output directory
OUTPUT_DIR="AppIcon.appiconset"
mkdir -p "$OUTPUT_DIR"

echo -e "${GREEN}Starting icon generation...${NC}"
echo "Source image: $SOURCE_ICON"
echo "Output directory: $OUTPUT_DIR"
echo ""

# Remove alpha channel and create base icon
echo -e "${YELLOW}Removing alpha channel...${NC}"
convert "$SOURCE_ICON" -alpha off -background white -flatten "$OUTPUT_DIR/icon-base.png"

# Function to generate icon
generate_icon() {
    local size=$1
    local filename=$2
    echo "  Generating $filename (${size}x${size}px)..."
    convert "$OUTPUT_DIR/icon-base.png" -resize ${size}x${size} "$OUTPUT_DIR/$filename"
}

# Generate all required sizes
echo -e "${YELLOW}Generating icon sizes...${NC}"

# iPhone Notification (iOS 7-15) 20pt
generate_icon 40 "Icon-App-20x20@2x.png"
generate_icon 60 "Icon-App-20x20@3x.png"

# iPhone Settings (iOS 7-15) 29pt
generate_icon 58 "Icon-App-29x29@2x.png"
generate_icon 87 "Icon-App-29x29@3x.png"

# iPhone Spotlight (iOS 7-15) 40pt
generate_icon 80 "Icon-App-40x40@2x.png"
generate_icon 120 "Icon-App-40x40@3x.png"

# iPhone App (iOS 7-15) 60pt
generate_icon 120 "Icon-App-60x60@2x.png"
generate_icon 180 "Icon-App-60x60@3x.png"

# iPad Notifications (iOS 7-15) 20pt
generate_icon 20 "Icon-App-20x20@1x.png"
# 40x40 already generated above

# iPad Settings (iOS 7-15) 29pt
generate_icon 29 "Icon-App-29x29@1x.png"
# 58x58 already generated above

# iPad Spotlight (iOS 7-15) 40pt
generate_icon 40 "Icon-App-40x40@1x.png"
# 80x80 already generated above

# iPad App (iOS 7-15) 76pt
generate_icon 76 "Icon-App-76x76@1x.png"
generate_icon 152 "Icon-App-76x76@2x.png"

# iPad Pro App (iOS 9-15) 83.5pt
generate_icon 167 "Icon-App-83.5x83.5@2x.png"

# App Store (iOS)
echo "  Generating ItunesArtwork@2x.png (1024x1024px)... ⭐ IMPORTANT for App Store"
generate_icon 1024 "ItunesArtwork@2x.png"

# Remove temporary base icon
rm "$OUTPUT_DIR/icon-base.png"

# Copy Contents.json
if [ -f "AppIcon_Contents.json" ]; then
    echo -e "${YELLOW}Copying Contents.json...${NC}"
    cp "AppIcon_Contents.json" "$OUTPUT_DIR/Contents.json"
else
    echo -e "${YELLOW}Creating Contents.json...${NC}"
    cat > "$OUTPUT_DIR/Contents.json" << 'EOF'
{
  "images" : [
    {
      "filename" : "Icon-App-20x20@2x.png",
      "idiom" : "iphone",
      "scale" : "2x",
      "size" : "20x20"
    },
    {
      "filename" : "Icon-App-20x20@3x.png",
      "idiom" : "iphone",
      "scale" : "3x",
      "size" : "20x20"
    },
    {
      "filename" : "Icon-App-29x29@2x.png",
      "idiom" : "iphone",
      "scale" : "2x",
      "size" : "29x29"
    },
    {
      "filename" : "Icon-App-29x29@3x.png",
      "idiom" : "iphone",
      "scale" : "3x",
      "size" : "29x29"
    },
    {
      "filename" : "Icon-App-40x40@2x.png",
      "idiom" : "iphone",
      "scale" : "2x",
      "size" : "40x40"
    },
    {
      "filename" : "Icon-App-40x40@3x.png",
      "idiom" : "iphone",
      "scale" : "3x",
      "size" : "40x40"
    },
    {
      "filename" : "Icon-App-60x60@2x.png",
      "idiom" : "iphone",
      "scale" : "2x",
      "size" : "60x60"
    },
    {
      "filename" : "Icon-App-60x60@3x.png",
      "idiom" : "iphone",
      "scale" : "3x",
      "size" : "60x60"
    },
    {
      "filename" : "Icon-App-20x20@1x.png",
      "idiom" : "ipad",
      "scale" : "1x",
      "size" : "20x20"
    },
    {
      "filename" : "Icon-App-20x20@2x.png",
      "idiom" : "ipad",
      "scale" : "2x",
      "size" : "20x20"
    },
    {
      "filename" : "Icon-App-29x29@1x.png",
      "idiom" : "ipad",
      "scale" : "1x",
      "size" : "29x29"
    },
    {
      "filename" : "Icon-App-29x29@2x.png",
      "idiom" : "ipad",
      "scale" : "2x",
      "size" : "29x29"
    },
    {
      "filename" : "Icon-App-40x40@1x.png",
      "idiom" : "ipad",
      "scale" : "1x",
      "size" : "40x40"
    },
    {
      "filename" : "Icon-App-40x40@2x.png",
      "idiom" : "ipad",
      "scale" : "2x",
      "size" : "40x40"
    },
    {
      "filename" : "Icon-App-76x76@1x.png",
      "idiom" : "ipad",
      "scale" : "1x",
      "size" : "76x76"
    },
    {
      "filename" : "Icon-App-76x76@2x.png",
      "idiom" : "ipad",
      "scale" : "2x",
      "size" : "76x76"
    },
    {
      "filename" : "Icon-App-83.5x83.5@2x.png",
      "idiom" : "ipad",
      "scale" : "2x",
      "size" : "83.5x83.5"
    },
    {
      "filename" : "ItunesArtwork@2x.png",
      "idiom" : "ios-marketing",
      "scale" : "1x",
      "size" : "1024x1024"
    }
  ],
  "info" : {
    "author" : "xcode",
    "version" : 1
  }
}
EOF
fi

echo ""
echo -e "${GREEN}✅ Success! All icons generated.${NC}"
echo ""
echo "Next steps:"
echo "1. Copy the entire '$OUTPUT_DIR' folder to:"
echo "   ios/CampusOne/Images.xcassets/"
echo ""
echo "2. Your folder structure should be:"
echo "   ios/CampusOne/Images.xcassets/AppIcon.appiconset/"
echo ""
echo "3. Open Xcode and verify the icons appear in the asset catalog"
echo ""
echo "4. Clean build and create a fresh archive:"
echo "   - Product → Clean Build Folder"
echo "   - Product → Archive"
echo ""
echo "5. Upload to App Store Connect"
echo ""
echo -e "${GREEN}The icons are ready in the '$OUTPUT_DIR' folder!${NC}"
